// lib/services/api-client.ts
import axios from 'axios';
import { getSession } from './auth';


const API_BASE_URL = process.env.NEXT_PUBLIC_API_URL || 
  (process.env.NODE_ENV === 'production' 
    ? 'https://api.aptiverse.co.za/api'
    : 'https://localhost:44390/api');

console.log('🔧 API Client Initialization:', {
  API_BASE_URL,
  NODE_ENV: process.env.NODE_ENV,
  hasNextPublicApiUrl: !!process.env.NEXT_PUBLIC_API_URL
});

const createApiClients = () => {
  let httpsAgent = undefined;
  
  if (process.env.NODE_ENV === 'development') {
    try {
      const https = require('https');
      httpsAgent = new https.Agent({
        rejectUnauthorized: false,
        keepAlive: true,
        maxSockets: 50,
      });
      console.log('🔧 HTTPS Agent created for development');
    } catch (error) {
      console.error('❌ Failed to create HTTPS agent:', error);
    }
  }

  const baseConfig = {
    baseURL: API_BASE_URL,
    headers: {
      'Content-Type': 'application/json',
    },
    timeout: 10000,
    ...(httpsAgent && { httpsAgent }),
  };

  console.log('🔧 Base Config:', {
    baseURL: baseConfig.baseURL,
    timeout: baseConfig.timeout,
    hasHttpsAgent: !!baseConfig.httpsAgent,
    headers: baseConfig.headers
  });

  const authClient = axios.create(baseConfig);
  const apiClient = axios.create(baseConfig);

  console.log('🔧 API Clients created');

  // Auth Client Interceptors
  authClient.interceptors.request.use(
    (config) => {
      console.log('🔐 Auth Client Request Interceptor:', {
        url: config.url,
        method: config.method,
        baseURL: config.baseURL,
        headers: Object.keys(config.headers)
      });
      return config;
    },
    (error) => {
      console.error('❌ Auth Client Request Error:', {
        message: error.message,
        code: error.code,
        config: error.config?.url
      });
      return Promise.reject(error);
    }
  );

  authClient.interceptors.response.use(
    (response) => {
      console.log('✅ Auth Client Response Success:', {
        url: response.config.url,
        status: response.status,
        statusText: response.statusText,
        dataKeys: response.data ? Object.keys(response.data) : 'no data'
      });
      return response;
    },
    (error) => {
      console.error('❌ Auth Client Response Error:', {
        message: error.message,
        code: error.code,
        status: error.response?.status,
        statusText: error.response?.statusText,
        url: error.config?.url,
        baseURL: error.config?.baseURL,
        responseData: error.response?.data
      });
      return Promise.reject(error);
    }
  );

  // API Client Interceptors
  apiClient.interceptors.request.use(
    (config) => {
      console.log('🔐 API Client Request Interceptor - Before Auth:', {
        url: config.url,
        method: config.method,
        baseURL: config.baseURL,
        headers: Object.keys(config.headers),
        hasAuthorization: !!config.headers.Authorization
      });
      return config;
    },
    (error) => {
      console.error('❌ API Client Request Interceptor Error:', {
        message: error.message,
        code: error.code,
        config: error.config?.url
      });
      return Promise.reject(error);
    }
  );

  apiClient.interceptors.response.use(
    (response) => {
      console.log('✅ API Client Response Success:', {
        url: response.config.url,
        status: response.status,
        statusText: response.statusText,
        dataLength: Array.isArray(response.data) ? response.data.length : 'object',
        hasData: !!response.data
      });
      return response;
    },
    (error) => {
      console.error('❌ API Client Response Error:', {
        message: error.message,
        code: error.code,
        status: error.response?.status,
        statusText: error.response?.statusText,
        url: error.config?.url,
        baseURL: error.config?.baseURL,
        headers: error.config?.headers,
        hasAuthorizationHeader: !!error.config?.headers?.Authorization,
        responseData: error.response?.data
      });
      
      // Log request details for 401 errors
      if (error.response?.status === 401) {
        console.error('🔐 401 Unauthorized Details:', {
          requestUrl: error.config?.url,
          requestMethod: error.config?.method,
          requestHeaders: error.config?.headers,
          fullRequest: error.request?._header
        });
      }
      
      return Promise.reject(error);
    }
  );

  return { authClient, apiClient };
};

const clients = createApiClients();

export const authClient = clients.authClient;
export const apiClient = clients.apiClient;

const getAuthToken = async (): Promise<string | null> => {
  console.log('🔑 getAuthToken called - Environment:', typeof window === 'undefined' ? 'Server' : 'Client');
  
  try {
    if (typeof window === 'undefined') {
      console.log('🔑 Server-side token retrieval');
      const { getServerSession } = await import('next-auth');
      const session = await getSession();
      
      console.log('🔑 Server Session Result:', {
        hasSession: !!session,
        sessionKeys: session ? Object.keys(session) : [],
        hasAccessToken: !!session?.accessToken,
        accessTokenPreview: session?.accessToken ? `${session.accessToken.substring(0, 20)}...` : 'none',
        user: session?.user
      });
      
      return session?.accessToken as string || null;
    } else {
      console.log('🔑 Client-side token retrieval');
      const session = await getSession();
      
      console.log('🔑 Client Session Result:', {
        hasSession: !!session,
        sessionKeys: session ? Object.keys(session) : [],
        hasAccessToken: !!session?.accessToken,
        accessTokenPreview: session?.accessToken ? `${session.accessToken.substring(0, 20)}...` : 'none',
        user: session?.user
      });
      
      return session?.accessToken as string || null;
    }
  } catch (error) {
    console.error('❌ Error getting auth token:', {
      error: error instanceof Error ? error.message : 'Unknown error',
      stack: error instanceof Error ? error.stack : undefined
    });
    return null;
  }
};

// Enhanced API Client Request Interceptor with detailed logging
apiClient.interceptors.request.use(
  async (config) => {
    console.log('🚀 API Client Request Interceptor - Starting:', {
      url: config.url,
      method: config.method,
      baseURL: config.baseURL,
      existingHeaders: Object.keys(config.headers),
      hasExistingAuth: !!config.headers.Authorization
    });

    try {
      const session = await getSession();
      const token = session?.accessToken;

      console.log('🔐 Token Retrieval Result:', {
        hasToken: !!token,
        tokenPreview: token ? `${token.substring(0, 20)}...` : 'none',
        tokenLength: token?.length
      });

      if (token) {
        config.headers.Authorization = `Bearer ${token}`;
        console.log('✅ Authorization Header Added:', {
          header: `Bearer ${token.substring(0, 20)}...`,
          allHeaders: Object.keys(config.headers)
        });
      } else {
        console.warn('⚠️ No token available for request');
      }

      // Log final request configuration
      console.log('📋 Final Request Config:', {
        url: config.url,
        method: config.method,
        headers: Object.keys(config.headers),
        hasAuthorization: !!config.headers.Authorization,
        baseURL: config.baseURL
      });

    } catch (error) {
      console.error('❌ Error in request interceptor:', {
        error: error instanceof Error ? error.message : 'Unknown error',
        stack: error instanceof Error ? error.stack : undefined
      });
    }
    
    return config;
  },
  (error) => {
    console.error('❌ Request interceptor error:', {
      message: error.message,
      code: error.code,
      config: error.config?.url
    });
    return Promise.reject(error);
  }
);

interface LoginData {
  email: string;
  password: string;
}

interface RegisterData {
  firstName: string;
  lastName: string;
  email: string;
  username: string;
  password: string;
  confirmPassword: string;
  userType: 'Superuser' | 'Admin' | 'Student' | 'Parent';
  phoneNumber?: string;
}

interface AuthResponse {
  user: {
    id: string;
    email: string;
    firstName: string;
    lastName: string;
    userType: string;
  };
  token: string;
  refreshToken: string;
}

export const authApi = {
  login: async (data: LoginData): Promise<AuthResponse> => {
    console.log('🔐 authApi.login called with:', { 
      email: data.email,
      passwordLength: data.password.length 
    });
    
    try {
      console.log('🔄 Making login request to:', `${API_BASE_URL}/auth/login`);
      const response = await authClient.post<AuthResponse>('/auth/login', data);
      
      console.log('✅ Login successful:', {
        user: response.data.user,
        hasToken: !!response.data.token,
        tokenPreview: response.data.token ? `${response.data.token.substring(0, 20)}...` : 'none'
      });
      
      return response.data;
    } catch (error: any) {
      console.error('❌ authApi.login failed:', {
        message: error.message,
        status: error.response?.status,
        statusText: error.response?.statusText,
        data: error.response?.data,
        config: error.config?.url
      });
      throw error;
    }
  },

  register: async (data: RegisterData): Promise<AuthResponse> => {
    console.log('🔐 authApi.register called with:', {
      email: data.email,
      firstName: data.firstName,
      lastName: data.lastName,
      userType: data.userType
    });
    
    const response = await authClient.post<AuthResponse>('/auth/register', data);
    
    console.log('✅ Registration successful:', {
      user: response.data.user,
      hasToken: !!response.data.token
    });
    
    return response.data;
  },
};

export const api = {
  get: <T>(url: string) => {
    console.log('📞 api.get called:', { url });
    return apiClient.get<T>(url)
      .then(response => {
        console.log('✅ api.get success:', { 
          url, 
          dataLength: Array.isArray(response.data) ? response.data.length : 'object' 
        });
        return response.data;
      })
      .catch(error => {
        console.error('❌ api.get failed:', { 
          url, 
          error: error.message,
          status: error.response?.status 
        });
        throw error;
      });
  },
  
  post: <T>(url: string, data?: any) => {
    console.log('📞 api.post called:', { url, data: data ? '***' : 'none' });
    return apiClient.post<T>(url, data)
      .then(response => {
        console.log('✅ api.post success:', { url, status: response.status });
        return response.data;
      })
      .catch(error => {
        console.error('❌ api.post failed:', { 
          url, 
          error: error.message,
          status: error.response?.status 
        });
        throw error;
      });
  },
  
  put: <T>(url: string, data?: any) => {
    console.log('📞 api.put called:', { url, data: data ? '***' : 'none' });
    return apiClient.put<T>(url, data)
      .then(response => {
        console.log('✅ api.put success:', { url, status: response.status });
        return response.data;
      })
      .catch(error => {
        console.error('❌ api.put failed:', { 
          url, 
          error: error.message,
          status: error.response?.status 
        });
        throw error;
      });
  },
  
  delete: <T>(url: string) => {
    console.log('📞 api.delete called:', { url });
    return apiClient.delete<T>(url)
      .then(response => {
        console.log('✅ api.delete success:', { url, status: response.status });
        return response.data;
      })
      .catch(error => {
        console.error('❌ api.delete failed:', { 
          url, 
          error: error.message,
          status: error.response?.status 
        });
        throw error;
      });
  },
};

console.log('✅ API Client setup complete');