import { authApi } from '@/lib/services/api-client'
import NextAuth from 'next-auth'
import CredentialsProvider from 'next-auth/providers/credentials'

const handler = NextAuth({
  secret: process.env.NEXTAUTH_SECRET,
  providers: [
    CredentialsProvider({
      name: 'credentials',
      credentials: {
        email: { label: 'Email', type: 'email' },
        password: { label: 'Password', type: 'password' }
      },
      async authorize(credentials) {
        try {
          console.log('🔐 Authorize called with:', { email: credentials?.email });
          
          const data = await authApi.login({
            email: credentials?.email || '',
            password: credentials?.password || '',
          })

          console.log('✅ Login successful:', { 
            hasToken: !!data.token,
            user: data.user 
          });

          if (data.token) {
            const user = {
              id: data.user.id,
              email: data.user.email,
              name: `${data.user.firstName} ${data.user.lastName}`,
              firstName: data.user.firstName,
              lastName: data.user.lastName,
              userType: data.user.userType,
              accessToken: data.token,
            }
            
            console.log('👤 User object for JWT:', user);
            return user as any;
          }

          return null;
        } catch (error: any) {
          console.error('❌ Authorize error:', error);
          if (error.response?.status === 401) {
            throw new Error('Invalid email or password');
          } else if (error.response?.status === 400) {
            throw new Error(error.response?.data?.message || 'Invalid request');
          } else if (error.response?.status >= 500) {
            throw new Error('Authentication service is temporarily unavailable');
          } else {
            throw new Error('Authentication failed. Please try again.');
          }
        }
      },
    }),
  ],
  callbacks: {
    async jwt({ token, user, trigger, session }) {
      console.log('🔄 JWT callback:', { 
        trigger,
        hasUser: !!user,
        tokenKeys: Object.keys(token),
        userKeys: user ? Object.keys(user) : []
      });
      
      // Initial sign in
      if (user) {
        console.log('✅ Adding user data to JWT');
        token.accessToken = (user as any).accessToken;
        token.user = {
          id: user.id,
          firstName: (user as any).firstName,
          lastName: (user as any).lastName,
          userName: (user as any).userName,
          email: user.email!,
          userType: (user as any).userType,
        };
      }
      
      console.log('🔐 Final JWT token:', {
        hasAccessToken: !!token.accessToken,
        accessTokenPreview: token.accessToken ? `${token.accessToken.substring(0, 20)}...` : 'none',
        user: token.user
      });
      
      return token;
    },
    async session({ session, token }) {
      console.log('🔄 Session callback:', {
        sessionUser: session.user,
        tokenUser: token.user,
        hasTokenAccessToken: !!token.accessToken,
        tokenKeys: Object.keys(token)
      });
      
      session.accessToken = token.accessToken as string;
      session.user = token.user as any;
      
      console.log('✅ Final session:', {
        hasAccessToken: !!session.accessToken,
        accessTokenPreview: session.accessToken ? `${session.accessToken.substring(0, 20)}...` : 'none',
        sessionUser: session.user
      });
      
      return session;
    },
  },
  pages: {
    signIn: '/login',
    error: '/login',
  },
  session: {
    strategy: 'jwt',
    maxAge: 30 * 24 * 60 * 60,
  },
  debug: process.env.NODE_ENV === 'development'
})

export { handler as GET, handler as POST }